// TOPIC_CHANNELS 파싱: 채널별 아이템 생성
// 형식: 채널이름/채널ID+채널이름/채널ID+...
const raw = ($env.TOPIC_CHANNELS || '').trim();
if (!raw) {
  return [{ json: { skip: true, reason: 'TOPIC_CHANNELS 미설정' } }];
}

const items = [];
const invalid = [];

for (const chunk of raw.split('+')) {
  const part = (chunk || '').trim();
  if (!part) continue;

  const slashIdx = part.indexOf('/');
  if (slashIdx < 0) {
    invalid.push(`${part}(구분자 '/' 없음)`);
    continue;
  }

  const channelName = part.slice(0, slashIdx).trim();
  const channelId = part.slice(slashIdx + 1).trim();

  if (!channelName || !channelId) {
    invalid.push(`${part}(채널명/채널ID 비어 있음)`);
    continue;
  }

  items.push({ json: { channelId, channelName } });
}

console.log(`[WF-09] parsed channels: valid=${items.length}, invalid=${invalid.length}`);
if (invalid.length) {
  console.log(`[WF-09] invalid TOPIC_CHANNELS entries: ${invalid.join(', ')}`);
}

if (!items.length) {
  return [{ json: { skip: true, reason: '유효한 채널 없음' } }];
}

return items;

// 채널별 YouTube RSS 조회 + 404/500 재시도 + 새 영상 필터링
const channelId = ($json.channelId || '').trim();
const channelName = ($json.channelName || '').trim();

if (!channelId) {
  return { json: { skip: true, channelId, channelName, reason: 'channelId 없음' } };
}

const rssUrl = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;

// 한 채널 처리 시간은 짧게 제한 (전체 실행 안정성)
const MAX_ATTEMPTS = 8;
const ATTEMPT_TIMEOUT_MS = 6000;
const MAX_TOTAL_MS = 60000;
const WAIT_MS = [1000, 1500, 2000, 2500, 3000, 4000, 5000];

const lookbackRaw = ($env.WF09_LOOKBACK_HOURS || '').trim();
const parsedLookback = Number.parseFloat(lookbackRaw);
const lookbackHours = Number.isFinite(parsedLookback) && parsedLookback > 0 ? parsedLookback : 24;
const CUTOFF_MS = Date.now() - lookbackHours * 60 * 60 * 1000;
const CUTOFF_ISO = new Date(CUTOFF_MS).toISOString();

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const decode = (s = '') => s
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

const parseXmlEntries = (xml) => {
  const list = [];
  const re = /<entry>([\s\S]*?)<\/entry>/g;
  let m;
  while ((m = re.exec(xml)) !== null) {
    const block = m[1];
    const videoId = (block.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1] || '';
    if (!videoId) continue;

    const title = (block.match(/<title>([^<]+)<\/title>/) || [])[1] || '';
    const publishedAt = (block.match(/<published>([^<]+)<\/published>/) || [])[1] || '';
    const linkMatch = block.match(/<link rel="alternate" href="([^"]+)"/);
    const link = linkMatch ? linkMatch[1] : `https://www.youtube.com/watch?v=${videoId}`;

    list.push({ videoId, title: decode(title), publishedAt, videoUrl: link });
  }
  return list;
};

const asArray = (v) => Array.isArray(v) ? v : (v == null ? [] : [v]);
const textOf = (v) => {
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return textOf(v[0]);
  if (!v || typeof v !== 'object') return '';
  if (typeof v._ === 'string') return v._;
  if (typeof v['#text'] === 'string') return v['#text'];
  return '';
};
const hrefOf = (linkVal) => {
  for (const l of asArray(linkVal)) {
    if (!l) continue;
    if (typeof l === 'string') return l;
    if (typeof l.href === 'string') return l.href;
    if (l.$ && typeof l.$.href === 'string') return l.$.href;
    if (l.attrs && typeof l.attrs.href === 'string') return l.attrs.href;
  }
  return '';
};
const parseObjEntries = (obj) => {
  const feed = obj && obj.feed ? obj.feed : obj;
  const rows = feed && feed.entry ? asArray(feed.entry) : [];
  const list = [];
  for (const r of rows) {
    if (!r || typeof r !== 'object') continue;
    const videoId = textOf(r['yt:videoId']) || textOf(r.videoId);
    if (!videoId) continue;
    const title = decode(textOf(r.title));
    const publishedAt = textOf(r.published) || textOf(r.updated);
    const link = hrefOf(r.link) || `https://www.youtube.com/watch?v=${videoId}`;
    list.push({ videoId, title, publishedAt, videoUrl: link });
  }
  return list;
};

let attemptsUsed = 0;
let fetchMode = '';
let entries = [];
let lastError = '';
const t0 = Date.now();

for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
  attemptsUsed = attempt;

  if (Date.now() - t0 >= MAX_TOTAL_MS) {
    lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_MS / 1000)}초 도달`;
    break;
  }

  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: rssUrl,
      options: { timeout: ATTEMPT_TIMEOUT_MS },
    });

    if (typeof resp === 'string') {
      if (resp.includes('<feed')) {
        entries = parseXmlEntries(resp);
        fetchMode = 'xml-string';
        console.log(`[WF-09] RSS success channel=${channelId} attempt=${attempt} mode=${fetchMode} entries=${entries.length}`);
        break; // 성공 즉시 재시도 중지
      }
      lastError = `문자열 응답이나 feed 없음(len=${resp.length})`;
    } else if (resp && typeof resp === 'object') {
      const candidate = (typeof resp.body === 'string' || typeof resp.body === 'object') ? resp.body : resp;
      if (typeof candidate === 'string' && candidate.includes('<feed')) {
        entries = parseXmlEntries(candidate);
        fetchMode = 'xml-string-in-body';
        console.log(`[WF-09] RSS success channel=${channelId} attempt=${attempt} mode=${fetchMode} entries=${entries.length}`);
        break; // 성공 즉시 중지
      }
      if (candidate && typeof candidate === 'object' && (candidate.feed || candidate.entry)) {
        entries = parseObjEntries(candidate);
        fetchMode = 'parsed-object';
        console.log(`[WF-09] RSS success channel=${channelId} attempt=${attempt} mode=${fetchMode} entries=${entries.length}`);
        break; // 성공 즉시 중지
      }
      lastError = '객체 응답이나 feed/entry 구조 없음';
    } else {
      lastError = `지원되지 않는 응답 타입(${typeof resp})`;
    }
  } catch (e) {
    lastError = e && e.message ? e.message : String(e);
    console.log(`[WF-09] RSS error channel=${channelId} attempt=${attempt}: ${lastError}`);
  }

  if (attempt < MAX_ATTEMPTS) {
    const elapsed = Date.now() - t0;
    if (elapsed >= MAX_TOTAL_MS) {
      lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_MS / 1000)}초 도달`;
      break;
    }
    const wait = WAIT_MS[Math.min(attempt - 1, WAIT_MS.length - 1)];
    await sleep(Math.min(wait, Math.max(0, MAX_TOTAL_MS - elapsed)));
  }
}

const executionMs = Date.now() - t0;

if (!fetchMode) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `RSS 재시도 종료(${lastError || 'unknown'})`,
      attemptsUsed,
      retryStrategy: 'retry-until-success-or-timebox',
      executionMs,
      lookbackHours,
      rssUrl,
    },
  };
}

if (!entries.length) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `RSS 성공 but entry 없음(mode=${fetchMode})`,
      attemptsUsed,
      executionMs,
      entriesTotal: 0,
      cutoffIso: CUTOFF_ISO,
      lookbackHours,
      rssUrl,
    },
  };
}

const fresh = [];
let skippedShorts = 0;
let skippedNoUrl = 0;
let skippedInvalidDate = 0;
let skippedOld = 0;
let latestPublishedMs = null;

for (const e of entries) {
  const url = e.videoUrl || `https://www.youtube.com/watch?v=${e.videoId}`;
  if (!url) {
    skippedNoUrl += 1;
    continue;
  }
  if (url.includes('/shorts/')) {
    skippedShorts += 1;
    continue;
  }

  const ts = Date.parse(e.publishedAt || '');
  if (!Number.isFinite(ts)) {
    skippedInvalidDate += 1;
    continue;
  }

  if (latestPublishedMs === null || ts > latestPublishedMs) {
    latestPublishedMs = ts;
  }

  if (ts < CUTOFF_MS) {
    skippedOld += 1;
    continue;
  }

  fresh.push({
    videoUrl: url,
    title: e.title || '',
    publishedAt: e.publishedAt || '',
    channelId,
    channelName,
    attemptsUsed,
    fetchMode,
    executionMs,
    entriesTotal: entries.length,
    cutoffIso: CUTOFF_ISO,
    lookbackHours,
    latestPublishedAt: new Date(latestPublishedMs).toISOString(),
  });
}

if (!fresh.length) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `새 영상 없음(최근 ${lookbackHours}시간, mode=${fetchMode})`,
      attemptsUsed,
      executionMs,
      entriesTotal: entries.length,
      latestPublishedAt: latestPublishedMs === null ? null : new Date(latestPublishedMs).toISOString(),
      cutoffIso: CUTOFF_ISO,
      lookbackHours,
      skippedOld,
      skippedShorts,
      skippedInvalidDate,
      skippedNoUrl,
      rssUrl,
    },
  };
}

// runOnceForEachItem 모드에서는 반드시 단일 item 객체를 반환해야 함
// 다수 후보가 있으면 최신 1건만 선택해서 다음 단계로 전달
let selected = fresh[0];
for (let i = 1; i < fresh.length; i++) {
  const current = fresh[i];
  if (Date.parse(current.publishedAt || '') > Date.parse(selected.publishedAt || '')) {
    selected = current;
  }
}

return {
  json: {
    ...selected,
    freshCount: fresh.length,
    selectedStrategy: 'latest-only-per-channel',
  },
};

// 결과 로깅
const result = $input.item.json;

if (result.duplicate) {
  console.log(`[WF-09] 중복 건너뜀`);
} else if (result.added) {
  console.log(`[WF-09] 소스 추가 완료 (cleaned=${result.cleaned_up})`);
} else if (result.error) {
  console.error(`[WF-09] 소스 추가 실패: ${result.error}`);
}

return { json: result };
